import {
  circle, ellipse, rectangle, polygon, segment,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones carrier silhouette — single ship, side view, minimal embellishment.
// (Intentionally minimal so scene-completion test has room to add peer subjects.)

// Hull
const hull = polygon([
  [-0.55, -0.08],
  [ 0.55, -0.08],
  [ 0.58, -0.16],
  [-0.55, -0.16],
]);

// Flight deck (overhangs hull slightly + ski-jump bow on right)
const deck = polygon([
  [-0.58, -0.08],
  [ 0.55, -0.08],
  [ 0.62, -0.02],
  [ 0.62,  0.02],
  [ 0.55,  0.04],
  [-0.58,  0.04],
]);

// Island superstructure (starboard, aft-of-center)
const islandBase = rectangle([0.16, 0.10], [0.18, 0.09]);
const islandMid  = rectangle([0.12, 0.06], [0.18, 0.17]);
const mast       = segment([0.18, 0.20], [0.18, 0.30], 0.005);

// Sea
const sea = rectangle([1.6, 0.5], [0, -0.40]);
const sky = rectangle([1.6, 0.5], [0,  0.40]);

const layers = [
  { sdf: sky,  color: [120, 160, 200] },
  { sdf: sea,  color: [30,  70, 120]  },
  { sdf: dilate(hull, 0.018), color: [20, 25, 35]  },
  { sdf: hull,                color: [70, 78, 92]  },
  { sdf: dilate(deck, 0.012), color: [20, 25, 35]  },
  { sdf: deck,                color: [105, 110, 120] },
  { sdf: dilate(islandBase, 0.010), color: [20, 25, 35] },
  { sdf: islandBase,          color: [85, 92, 105]  },
  { sdf: islandMid,           color: [85, 92, 105]  },
  { sdf: mast,                color: [20, 25, 35]   },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [110, 145, 185], bottom: [185, 210, 225] },
});
```

**Composition notes**: Bare carrier silhouette — hull + ski-jump flight deck + small island + mast. NO escort ships, NO birds, NO clouds, NO planes on deck (intentionally minimal). The 2D scene shows ONE ship in featureless sea. The 3D lift should INFER the full scene: escort fleet around the carrier, gulls overhead, distant clouds, waves — this is scene completion territory.
